    source: "bip",
    resume: "=== Résorption de l'emploi précaire (Loi n°2001-2 du 3 janvier 2001) ===\n\nII. AGENTS CONCERNES\n\nIII. MODALITES D'INTEGRATION\n\nIV. EFFETS DE L'INTEGRAT...",
    localPath: "/bip/output/bip_fiches_rag_agents-contractuels_20260227_105025/agents-contractuels_dispositifs-de-resorption-de-la-precarite_reempr.md",
    section: "agents-contractuels",
