    motsCles: ["iii","ntirec","maladie","cong","cmo","cdd","caa","madrob","ntiint","cgm","agents","contractuels","conmed","cpam","congés","url","nticas","fncdg","dgafp","delcar","ald","grave","clm","pacte","pour","accident","travail","entre","curit","sociale","contr","dical","agent","apr","temthe"],
    source: "bip",
    resume: "=== Agents contractuels : les congés de maladie ===\n\nIV. COORDINATION ENTRE TRAITEMENT ET PRESTATIONS DE LA SÉCURITÉ SOCIALE\n\nA) L’articulation entre ...",
    localPath: "/bip/output/bip_fiches_rag_agents-contractuels_20260227_105025/conges-et-absences_conges-des-agents-contractuels_ntico3.md",
