    motsCles: ["ldg","graf","des","tabava","lidige","caa","avaech","avagra","principe","iii","fixation","taux","lignes","gestion","vii","cas","dispon","avancement","grade","carriere","url","iaj","proint","activi","fondet","sicopa","sereff","tepaef","genfon","spp","cjue","fpt","avaadm","avaatt","avainch","avaing","avacod","avgrar","nes"],
    source: "bip",
    resume: "=== Avancement de grade ===\n\nII. FONCTIONNAIRES CONCERNES\n\nIII. CONDITIONS\n\nIV. FIXATION DU TAUX DE PROMOTION\n\nV. ELABORATION DES LIGNES DIRECTRICES D...",
    localPath: "/bip/output/bip_fiches_rag_carriere_20260227_140229/carriere_avancement_avagra.md",
    section: "carriere",
