    source: "bip",
    resume: "=== Tableau annuel d'avancement ===\n\nI. PRINCIPES GENERAUX\n\nIII. ETABLISSEMENT DU TABLEAU\n\nIV. PORTEE JURIDIQUE DU TABLEAU\n\nV. RECOURS\n\nLes décisions ...",
    localPath: "/bip/output/bip_fiches_rag_carriere_20260227_140229/carriere_avancement_tabava.md",
    section: "carriere",
