    source: "bip",
    resume: "=== Cessation des fonctions opérationnelles des sapeurs-pompiers professionnels ===\n\nI. ELEMENTS GENERAUX DE PROCEDURE\n\nII. L'AFFECTATION A DES FONCTI...",
    localPath: "/bip/output/bip_fiches_rag_indisponibilite-physique-et-securite-sociale_20260227_102823/indisponibilite-physique-et-securite-sociale_projet-de-fin-de-carriere-des-sapeurs-pompiers_finsap.md",
